import { StoreMessage, StoreMessageMap } from './types';
import type { Runtime } from 'webextension-polyfill';
import { browser_api } from '@app/browser_api';
import { logger } from '@utils/logger';

export function isStoreMessageOfType<T extends StoreMessage['action']>(
  msg: unknown,
  action: T,
): msg is Extract<StoreMessage, { action: T }> {
  return (
    typeof msg === 'object' &&
    msg !== null &&
    'action' in msg &&
    (msg as any).action === action
  );
}

export function postMessageHandler<T extends keyof StoreMessageMap>(
  port: Runtime.Port,
  action: T,
  payload: StoreMessageMap[T],
): boolean {
  try {
    port.postMessage({
      action,
      payload,
      origin,
    });

    if (browser_api.runtime.lastError) {
      console.warn(
        'Message port closed, likely due to bfcache:',
        browser_api.runtime.lastError.message,
      );
      return false; // Порт закрыт
    }

    return true; // Сообщение отправлено успешно
  } catch (error) {
    logger.error(
      'postMessageHandler: Failed to send message through port:',
      error,
    );
    return false; // Ошибка отправки
  }
}
